svg.script:
var SVG_NS = "http://www.w3.org/2000/svg";
var XLINK  = "http://www.w3.org/1999/xlink";

var state = {
  loggedIn: false,
  dropdownOpen: false,
  modalOpen: false,        // add-jurisdiction spotlight
  authView: null,          // logged-out auth flow: null | "choose" | "register" | "verify" | "login"
  otpAllowed: false,       // account's OTP-login-allow window open (toggle: O) — adds email-code login
  profileOpen: false,      // profile modal (logged-in only)
  labelsOn: true,
  page: "feed",            // "feed" | "other"
  kyc: 0,                  // 0 unverified · 1 identity · 2 residency
  deviceCount: 3,          // passkeys/devices on the account
  theme: "Light",          // "Light" | "Dark" — UI preference toggle only
  filterOpen: false,       // feed filter dropdown (left button)
  // record-type filter — same min-1 / exclusive-select interlock as jurisdictions
  recordTypes: [
    { name: "Statements", icon: "#ic-message",      included: true },
    { name: "Petitions",  icon: "#ic-clipboard",    included: true },
    { name: "Polls",      icon: "#ic-bar",          included: true },
    { name: "Results",    icon: "#ic-check-circle", included: true }
  ],
  verified: 0,             // min author verification: 0 None · 1 ID · 2 Residency
  myDistricts: false,      // limit to my districts — independent of record types (off by default)
  // compose flow (new-post FAB): where → type → compose
  composeStep: null,       // null | "where" | "type" | "compose"
  composeJur: null,        // chosen jurisdiction name
  composeType: null,       // chosen root key: "statement" | "petition" | "poll"
  composeJurOpen: false,   // jurisdiction dropdown inside the compose modal
  pollOptions: ["", ""],   // poll compose: ≥2 options, add up to the jurisdiction max
  pollScroll: 0,           // poll options scroll offset (px) once the list exceeds 5 rows
  petitionSupport: "Sign the Petition", // petition compose: customizable signature CTA (≤60) — PROPOSED field
  // subscribed jurisdictions: persisted to a cookie (works logged-out).
  // `included` drives the unified-feed filter.
  subs: [{ name: "Global", icon: "#ic-globe", included: true }]
};

var KYC_TIERS = ["Unverified", "Identity Verified", "Residency Verified"];
var VERIFIED_LEVELS = ["None", "ID", "Residency"];

// postable root types and the roots each jurisdiction allows (default = all).
// Alberta accepts statements + petitions only; a 1-root jurisdiction skips the type step.
var ROOT_TYPES = [
  { key: "statement", label: "Statement", icon: "#ic-message" },
  { key: "petition",  label: "Petition",  icon: "#ic-clipboard" },
  { key: "poll",      label: "Poll",      icon: "#ic-bar" }
];
var JUR_ROOTS = { "Global": ["statement", "petition", "poll"], "Alberta": ["statement", "petition"] };
function rootsFor(name) { return JUR_ROOTS[name] || ["statement", "petition", "poll"]; }
function rootMeta(key) { return ROOT_TYPES.filter(function (r) { return r.key === key; })[0] || ROOT_TYPES[0]; }
function subByName(name) { return state.subs.filter(function (s) { return s.name === name; })[0]; }

// NOTE(tech) compose-editor config — wire these to JurisdictionConfig.contentLimits, do not hardcode:
//   pollMax  → contentLimits.maxPollOptions (spec: ≤10; see docs/entities/civic-content/poll.md)
//   SUPPORT_LABEL_MAX → PROPOSED petition field (see petition.md gap [proposed-petition-support-label])
var SUPPORT_LABEL_MAX = 60;
function pollMax(name) { return 10; }

function $(id) { return document.getElementById(id); }
function show(el, on) { el.setAttribute("display", on ? "inline" : "none"); }

function icon(href, x, y, size, stroke) {
  var u = document.createElementNS(SVG_NS, "use");
  u.setAttribute("href", href);
  u.setAttributeNS(XLINK, "href", href);
  u.setAttribute("x", x); u.setAttribute("y", y);
  u.setAttribute("width", size); u.setAttribute("height", size);
  u.setAttribute("stroke", stroke);
  return u;
}
function txt(x, y, s, size, fill) {
  var t = document.createElementNS(SVG_NS, "text");
  t.setAttribute("x", x); t.setAttribute("y", y);
  t.setAttribute("font-size", size || 15);
  t.setAttribute("fill", fill || "#333");
  t.textContent = s;
  return t;
}
function rect(x, y, w, h, rx, fill, stroke) {
  var r = document.createElementNS(SVG_NS, "rect");
  r.setAttribute("x", x); r.setAttribute("y", y);
  r.setAttribute("width", w); r.setAttribute("height", h);
  r.setAttribute("rx", rx); r.setAttribute("fill", fill);
  if (stroke) r.setAttribute("stroke", stroke);
  return r;
}
function clamp(v, lo, hi) { return Math.max(lo, Math.min(hi, v)); }

// a centred row of six OTP code boxes (mock; no real entry) appended to `parent`
function otpRow(parent, centerX, y, sample) {
  var bw = 36, gap = 6, n = 6, total = n * bw + (n - 1) * gap, x0 = centerX - total / 2;
  for (var i = 0; i < n; i++) {
    var bx = x0 + i * (bw + gap);
    parent.appendChild(rect(bx, y, bw, 42, 6, "#f7f7f7", "#ddd"));
    var t = txt(bx + bw / 2, y + 29, sample[i] || "", 17, "#bbb");
    t.setAttribute("text-anchor", "middle");
    parent.appendChild(t);
  }
}

// ---- jurisdiction dropdown interior (built from state.subs) -------------
var DD_X = 97, DD_W = 236, DD_TOP = 106, ROW_H = 40, PAD = 8;

function buildDropdown() {
  var inner = $("ddInner");
  while (inner.firstChild) inner.removeChild(inner.firstChild);

  // checkboxes only make sense once there is more than one jurisdiction to filter
  var hasCheckbox = state.subs.length > 1;
  var iconX = hasCheckbox ? DD_X + 40 : DD_X + 16;
  var nameX = hasCheckbox ? DD_X + 66 : DD_X + 42;

  var y = DD_TOP + PAD;
  state.subs.forEach(function (item) {
    var rowY = y;
    var row = document.createElementNS(SVG_NS, "g");
    row.style.cursor = "pointer";
    row.appendChild(rect(DD_X + 4, rowY, DD_W - 8, ROW_H, 8, "#ffffff"));

    // tapping a row (its name) switches the feed to ONLY that jurisdiction
    row.addEventListener("click", function () { selectOnly(item); });

    if (hasCheckbox) {
      // include checkbox toggles multi-select inclusion (overrides the row's select-only)
      var cb = document.createElementNS(SVG_NS, "g");
      cb.style.cursor = "pointer";
      cb.appendChild(rect(DD_X + 12, rowY + 11, 18, 18, 4, item.included ? "#333" : "#ffffff", "#333"));
      if (item.included) cb.appendChild(icon("#ic-check", DD_X + 13, rowY + 12, 16, "#ffffff"));
      cb.addEventListener("click", function (e) {
        e.stopPropagation();
        var includedCount = state.subs.filter(function (s) { return s.included; }).length;
        if (item.included && includedCount <= 1) return; // keep ≥1 selected (never None)
        item.included = !item.included;
        render();
      });
      row.appendChild(cb);
    }

    // jurisdiction icon + name
    row.appendChild(icon(item.icon, iconX, rowY + 11, 18, "#333"));
    row.appendChild(txt(nameX, rowY + 25, item.name, 15, "#333"));

    // external-open → open this jurisdiction's page: select ONLY it + flip off the
    // Feed (so the FAB shows the newspaper "go to Feed" icon)
    var ext = document.createElementNS(SVG_NS, "g");
    ext.style.cursor = "pointer";
    var extHit = rect(DD_X + DD_W - 42, rowY + 4, 34, 34, 6, "#000"); // full clickable target
    extHit.setAttribute("opacity", "0");                              // (the bare glyph only
    ext.appendChild(extHit);                                          //  hit on its strokes)
    ext.appendChild(icon("#ic-external", DD_X + DD_W - 34, rowY + 11, 18, "#666"));
    ext.addEventListener("click", function (e) {
      e.stopPropagation();
      state.subs.forEach(function (s) { s.included = (s === item); });
      state.page = "other";        // a jurisdiction page (not the Feed)
      state.dropdownOpen = false;
      render();
    });
    row.appendChild(ext);

    inner.appendChild(row);
    y += ROW_H;
  });

  // full-width "+ Add Jurisdiction" button
  var addY = y + 4;
  var btn = document.createElementNS(SVG_NS, "g");
  btn.style.cursor = "pointer";
  var bRect = rect(DD_X + 8, addY, DD_W - 16, 36, 8, "#f2f2f2", "#333");
  bRect.setAttribute("stroke-dasharray", "4 3");
  btn.appendChild(bRect);
  btn.appendChild(icon("#ic-plus", DD_X + 44, addY + 10, 16, "#333"));
  var bt = txt(DD_X + DD_W / 2 + 10, addY + 23, "Add Jurisdiction", 14, "#333");
  bt.setAttribute("text-anchor", "middle");
  btn.appendChild(bt);
  btn.addEventListener("click", openModal);
  inner.appendChild(btn);

  $("ddBg").setAttribute("height", (addY + 36 + PAD) - DD_TOP);
}

function pillLabel() {
  var inc = state.subs.filter(function (s) { return s.included; });
  if (inc.length === 0) return "None";
  if (inc.length === 1) return inc[0].name;
  return inc.length + " selected";
}

// tap a jurisdiction name → show ONLY that one (deselect the rest) and open the
// Feed (so the FAB is the compose/quill post button)
function selectOnly(item) {
  state.subs.forEach(function (s) { s.included = (s === item); });
  state.page = "feed";         // its Feed → FAB shows the compose (new-post) icon
  state.dropdownOpen = false;
  render();
}

// ---- feed filter dropdown interior (record types + refine) --------------
var FD_X = 28, FD_W = 250, FD_TOP = 106, FROW_H = 38, FPAD = 8;

// a ✓ checkbox cell reflecting `on`; runs onToggle (already stops propagation)
function checkbox(x, y, on, onToggle) {
  var cb = document.createElementNS(SVG_NS, "g");
  cb.style.cursor = "pointer";
  cb.appendChild(rect(x, y, 18, 18, 4, on ? "#333" : "#ffffff", "#333"));
  if (on) cb.appendChild(icon("#ic-check", x + 1, y + 1, 16, "#ffffff"));
  cb.addEventListener("click", function (e) { e.stopPropagation(); onToggle(); });
  return cb;
}
function sectionHdr(x, y, s) {
  var t = txt(x, y, s, 12, "#999");
  t.setAttribute("font-weight", "bold");
  return t;
}
function filterRow(y) {
  var row = document.createElementNS(SVG_NS, "g");
  row.style.cursor = "pointer";
  row.appendChild(rect(FD_X + 4, y, FD_W - 8, FROW_H, 8, "#ffffff"));
  return row;
}

function buildFilter() {
  var inner = $("fdInner");
  while (inner.firstChild) inner.removeChild(inner.firstChild);

  var y = FD_TOP + FPAD;

  // --- section 1: record types (min-1 multi-include + exclusive body select) ---
  inner.appendChild(sectionHdr(FD_X + 16, y + 14, "Record types"));
  y += 24;

  // "All Records" — quick select-all button (no checkbox)
  var allRowY = y, allRow = filterRow(allRowY);
  allRow.addEventListener("click", function () {
    state.recordTypes.forEach(function (t) { t.included = true; });
    render();
  });
  allRow.appendChild(icon("#ic-list", FD_X + 12, allRowY + 10, 18, "#333"));
  var allLbl = txt(FD_X + 40, allRowY + 25, "All Records", 14, "#333");
  allLbl.setAttribute("font-weight", "bold");
  allRow.appendChild(allLbl);
  inner.appendChild(allRow);
  y += FROW_H;

  state.recordTypes.forEach(function (item) {
    var rowY = y, row = filterRow(rowY);
    row.addEventListener("click", function () { selectTypeOnly(item); }); // body → only this
    row.appendChild(checkbox(FD_X + 12, rowY + 10, item.included, function () {
      var inc = state.recordTypes.filter(function (t) { return t.included; }).length;
      if (item.included && inc <= 1) return; // keep ≥1 selected (never None)
      item.included = !item.included;
      render();
    }));
    row.appendChild(icon(item.icon, FD_X + 40, rowY + 10, 18, "#333"));
    row.appendChild(txt(FD_X + 66, rowY + 25, item.name, 14, "#333"));
    inner.appendChild(row);
    y += FROW_H;
  });

  // --- section 2: refine (independent of the record-type interlock) ---
  y += 8;
  inner.appendChild(sectionHdr(FD_X + 16, y + 14, "Refine"));
  y += 24;

  // verified — value toggle: None / ID / Residency (dimmed when None, like My districts)
  var vRowY = y, vRow = filterRow(vRowY);
  var vOn = state.verified > 0;
  vRow.appendChild(icon("#ic-shield", FD_X + 12, vRowY + 10, 18, vOn ? "#333" : "#999"));
  vRow.appendChild(txt(FD_X + 42, vRowY + 25, "Verified", 14, vOn ? "#333" : "#999"));
  var vVal = txt(FD_X + FD_W - 16, vRowY + 25, VERIFIED_LEVELS[state.verified], 13, vOn ? "#555" : "#999");
  vVal.setAttribute("text-anchor", "end");
  vRow.appendChild(vVal);
  vRow.addEventListener("click", function () {
    state.verified = (state.verified + 1) % VERIFIED_LEVELS.length;
    // dropping below Residency drops My Districts (it requires a residency-scoped feed)
    if (state.verified !== 2) state.myDistricts = false;
    render();
  });
  inner.appendChild(vRow);
  y += FROW_H;

  // my districts — eye / eye-off. ONLY available to residency-verified accounts (kyc === 2).
  // Interlock: turning it on jumps Verified → Residency; Verified leaving Residency drops it.
  // NOTE(tech): gate on the account's residency tier (or higher elector tier, future).
  var dRowY = y, dRow = filterRow(dRowY);
  var canDistricts = state.kyc === 2;            // residency-verified account required
  var dOn = state.myDistricts && canDistricts;
  var dCol = !canDistricts ? "#ccc" : (dOn ? "#333" : "#999");
  var eye = icon(dOn ? "#ic-eye" : "#ic-eye-off", FD_X + 11, dRowY + 10, 20, dCol);
  dRow.appendChild(eye);
  dRow.appendChild(txt(FD_X + 42, dRowY + 25, "My Districts", 14, dCol));
  if (canDistricts) {
    var toggleDistricts = function () {
      state.myDistricts = !state.myDistricts;
      if (state.myDistricts) state.verified = 2; // my districts ⇒ residency-verified authors
      render();
    };
    eye.style.cursor = "pointer";
    eye.addEventListener("click", function (e) { e.stopPropagation(); toggleDistricts(); });
    dRow.addEventListener("click", toggleDistricts);
  } else {
    var note = txt(FD_X + FD_W - 16, dRowY + 25, "Residency only", 11, "#bbb");
    note.setAttribute("text-anchor", "end");
    dRow.appendChild(note);
    dRow.style.cursor = "default";
  }
  inner.appendChild(dRow);
  y += FROW_H;

  $("fdBg").setAttribute("height", (y + FPAD) - FD_TOP);
}

// tap a record-type name → show ONLY that type (deselect the rest)
function selectTypeOnly(item) {
  state.recordTypes.forEach(function (t) { t.included = (t === item); });
  render(); // keep the panel open — more sections below
}

// ---- compose flow (new-post FAB): where → type → compose -----------------
function startCompose() {
  state.dropdownOpen = false; state.filterOpen = false; state.modalOpen = false;
  state.composeJurOpen = false;
  var sel = state.subs.filter(function (s) { return s.included; });
  if (sel.length > 1) { state.composeJur = null; state.composeStep = "where"; render(); }
  else { enterType(sel[0].name); }                 // exactly one selected → assume it
}
// chosen (or assumed) jurisdiction → type step, skipped when only one root is allowed
function enterType(name) {
  state.composeJur = name;
  var roots = rootsFor(name);
  if (roots.length === 1) { state.composeType = roots[0]; state.composeStep = "compose"; }
  else {
    if (roots.indexOf(state.composeType) === -1) state.composeType = null; // drop a now-invalid type
    state.composeStep = "type";
  }
  state.composeJurOpen = false;
  render();
}
function enterCompose(key) {
  state.composeType = key;
  if (key === "poll") { state.pollOptions = ["", ""]; state.pollScroll = 0; } // fresh Yes/No baseline
  if (key === "petition") state.petitionSupport = "Sign the Petition"; // default signature CTA
  state.composeStep = "compose";
  render();
}

// "Where do you want to post" — the selected jurisdictions
function buildWhere() {
  var inner = $("whereInner");
  while (inner.firstChild) inner.removeChild(inner.firstChild);
  var X = 55, W = 320, TOP = 296, RH = 44, y = TOP;
  state.subs.filter(function (s) { return s.included; }).forEach(function (item) {
    var rowY = y, row = document.createElementNS(SVG_NS, "g");
    row.style.cursor = "pointer";
    row.appendChild(rect(X + 12, rowY, W - 24, RH - 6, 8, "#ffffff", "#ddd"));
    row.appendChild(icon(item.icon, X + 26, rowY + 9, 20, "#333"));
    row.appendChild(txt(X + 54, rowY + 25, item.name, 15, "#333"));
    row.appendChild(icon("#ic-chevron-right", X + W - 40, rowY + 9, 20, "#999"));
    row.addEventListener("click", function () { enterType(item.name); });
    inner.appendChild(row);
    y += RH;
  });
  $("whereCard").setAttribute("height", (y + 16) - 210);
}

// post-type picker — the roots the chosen jurisdiction allows
function buildType() {
  var inner = $("typeInner");
  while (inner.firstChild) inner.removeChild(inner.firstChild);
  $("typeSubtitle").textContent = "In " + (state.composeJur || "Global");
  var X = 55, W = 320, TOP = 316, RH = 52, y = TOP;
  rootsFor(state.composeJur).forEach(function (key) {
    var rm = rootMeta(key), rowY = y, row = document.createElementNS(SVG_NS, "g");
    row.style.cursor = "pointer";
    row.appendChild(rect(X + 12, rowY, W - 24, RH - 8, 8, "#ffffff", "#ddd"));
    row.appendChild(icon(rm.icon, X + 28, rowY + 11, 22, "#333"));
    row.appendChild(txt(X + 62, rowY + 28, rm.label, 15, "#333"));
    row.appendChild(icon("#ic-chevron-right", X + W - 40, rowY + 12, 20, "#999"));
    row.addEventListener("click", function () { enterCompose(key); });
    inner.appendChild(row);
    y += RH;
  });
  $("typeCard").setAttribute("height", (y + 16) - 230);
}

// jurisdiction dropdown inside the compose editor — unsupported roots are greyed out
function buildComposeJurMenu() {
  var inner = $("composeJurInner");
  while (inner.firstChild) inner.removeChild(inner.firstChild);
  var X = 68, W = 210, TOP = 346, RH = 36, y = TOP;
  state.subs.forEach(function (item) {
    var supported = rootsFor(item.name).indexOf(state.composeType) !== -1;
    var col = supported ? "#333" : "#bbb", rowY = y;
    var row = document.createElementNS(SVG_NS, "g");
    row.appendChild(rect(X + 4, rowY, W - 8, RH, 6, "#ffffff"));
    row.appendChild(icon(item.icon, X + 12, rowY + 9, 18, col));
    row.appendChild(txt(X + 38, rowY + 23, item.name, 13.5, col));
    if (supported) {
      row.style.cursor = "pointer";
      if (item.name === state.composeJur) row.appendChild(icon("#ic-check", X + W - 28, rowY + 9, 16, "#333"));
      row.addEventListener("click", function (e) { e.stopPropagation(); state.composeJur = item.name; state.composeJurOpen = false; render(); });
    } else {
      var na = txt(X + W - 12, rowY + 23, "type N/A", 10.5, "#bbb");
      na.setAttribute("text-anchor", "end");
      row.appendChild(na);
    }
    inner.appendChild(row);
    y += RH;
  });
  $("composeJurBg").setAttribute("height", (y + 6) - TOP);
}

// ---- compose editor (type-specific fields) -------------------------------
function fieldLbl(x, y, s) { var t = txt(x, y, s, 10.5, "#999"); t.setAttribute("font-weight", "bold"); return t; }
function inputBox(x, y, w, h, ph, phCol) {
  var g = document.createElementNS(SVG_NS, "g");
  g.appendChild(rect(x, y, w, h, 6, "#f7f7f7", "#ddd"));
  g.appendChild(txt(x + 12, y + 21, ph, 12, phCol || "#bbb"));
  return g;
}
function dashBtn(x, y, w, label, onClick) {
  var g = document.createElementNS(SVG_NS, "g"); g.style.cursor = "pointer";
  var r = rect(x, y, w, 32, 8, "#f2f2f2", "#333"); r.setAttribute("stroke-dasharray", "4 3");
  g.appendChild(r);
  g.appendChild(icon("#ic-plus", x + 12, y + 8, 16, "#333"));
  g.appendChild(txt(x + 34, y + 21, label, 13, "#333"));
  g.addEventListener("click", function (e) { e.stopPropagation(); onClick(); });
  return g;
}
function removeBtn(x, y, onClick) {
  var g = document.createElementNS(SVG_NS, "g"); g.style.cursor = "pointer";
  var hit = rect(x, y, 24, 24, 6, "#000"); hit.setAttribute("opacity", "0");
  g.appendChild(hit);
  g.appendChild(icon("#ic-x", x + 3, y + 3, 18, "#999"));
  g.addEventListener("click", function (e) { e.stopPropagation(); onClick(); });
  return g;
}

// build the per-type editor and size the card to fit; returns nothing
function buildComposeEditor() {
  var g = $("composeEditor");
  while (g.firstChild) g.removeChild(g.firstChild);
  var X = 68, W = 290, y = 356, type = state.composeType, rm = rootMeta(type);

  // title / question (every type)
  var isPoll = type === "poll";
  g.appendChild(fieldLbl(X, y, isPoll ? "Question" : "Title"));
  g.appendChild(inputBox(X, y + 8, W, 34,
    isPoll ? "Ask a yes/no or multiple-choice question…"
           : (type === "petition" ? "What are you calling for?" : "A clear headline…")));
  y += 52;

  if (isPoll) {
    // options — ≥2 baseline; the list grows the card up to 5 rows, then the 6th+ scroll
    // inside a fixed 5-row viewport (the card never grows past 5). Add up to the jur max.
    g.appendChild(fieldLbl(X, y, "Options"));
    y += 14;
    var ROWH = 36, n = state.pollOptions.length, visRows = Math.min(n, 5);
    var vpTop = y, vpH = visRows * ROWH, contentH = n * ROWH;
    var maxScroll = Math.max(0, contentH - vpH);
    state.pollScroll = clamp(state.pollScroll, 0, maxScroll);

    // clipped viewport: rows live in an inner group translated by the scroll offset
    $("pollOptClipRect").setAttribute("x", X - 4);
    $("pollOptClipRect").setAttribute("y", vpTop - 2);
    $("pollOptClipRect").setAttribute("width", W + 12);
    $("pollOptClipRect").setAttribute("height", vpH + 4);
    var clipG = document.createElementNS(SVG_NS, "g");
    clipG.setAttribute("clip-path", "url(#pollOptClip)");
    var innerG = document.createElementNS(SVG_NS, "g");
    innerG.setAttribute("transform", "translate(0," + (-state.pollScroll) + ")");
    state.pollOptions.forEach(function (opt, i) {
      var rowY = vpTop + i * ROWH;
      innerG.appendChild(inputBox(X, rowY, W - 34, 32, opt || ("Option " + (i + 1)), opt ? "#333" : "#bbb"));
      if (n > 2) innerG.appendChild(removeBtn(X + W - 26, rowY + 4, function () { state.pollOptions.splice(i, 1); render(); }));
    });
    clipG.appendChild(innerG);
    // wheel-to-scroll (only meaningful once scrollable)
    if (maxScroll > 0) {
      clipG.addEventListener("wheel", function (e) {
        e.preventDefault();
        state.pollScroll = clamp(state.pollScroll + e.deltaY, 0, maxScroll);
        render();
      }, { passive: false });
    }
    g.appendChild(clipG);

    // scrollbar thumb (right edge of the viewport) when there is overflow
    if (maxScroll > 0) {
      var trackX = X + W + 2, thumbH = Math.max(24, vpH * vpH / contentH);
      var thumbY = vpTop + (state.pollScroll / maxScroll) * (vpH - thumbH);
      g.appendChild(rect(trackX, vpTop, 4, vpH, 2, "#eee"));
      g.appendChild(rect(trackX, thumbY, 4, thumbH, 2, "#bbb"));
    }
    y = vpTop + vpH + 6;

    var max = pollMax(state.composeJur);
    if (n < max) {
      g.appendChild(dashBtn(X, y, 150, "Add option", function () { state.pollOptions.push(""); render(); }));
      y += 42;
    } else {
      g.appendChild(txt(X, y + 14, "Maximum " + max + " options reached", 11, "#999"));
      y += 26;
    }
    // NOTE(tech): option count cap is per-jurisdiction (contentLimits.maxPollOptions, default 10)
  } else {
    // body (statement + petition)
    g.appendChild(fieldLbl(X, y, "Body"));
    g.appendChild(inputBox(X, y + 8, W, 96, "Write your " + rm.label.toLowerCase() + "…"));
    y += 116;

    if (type === "petition") {
      // PROPOSED: customizable signature call-to-action ("support statement"), max 60 chars
      g.appendChild(fieldLbl(X, y, "Support statement (signature button)"));
      var box = inputBox(X, y + 8, W, 34, state.petitionSupport, "#333");
      var counter = txt(X + W - 10, y + 29, state.petitionSupport.length + "/" + SUPPORT_LABEL_MAX, 10.5, "#999");
      counter.setAttribute("text-anchor", "end");
      box.appendChild(counter);
      g.appendChild(box);
      y += 48;
      g.appendChild(txt(X, y + 8, "Defaults to “Sign the Petition” · editable, max 60", 10.5, "#999"));
      y += 22;
    }
  }

  // post (mock submit → back to Feed) + dismissal hint
  var post = document.createElementNS(SVG_NS, "g"); post.style.cursor = "pointer";
  post.appendChild(rect(X, y + 6, W, 44, 10, "#333"));
  var pt = txt(X + W / 2, y + 34, "Post", 15, "#ffffff");
  pt.setAttribute("text-anchor", "middle"); pt.setAttribute("font-weight", "bold");
  post.appendChild(pt);
  post.addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });
  g.appendChild(post);
  y += 58;

  var hint = txt(X + W / 2, y + 8, "Alt: Esc or tap outside to close", 11, "#999");
  hint.setAttribute("text-anchor", "middle");
  g.appendChild(hint);
  y += 18;

  $("composeCard").setAttribute("height", (y + 10) - 170);
}

// ---- modals --------------------------------------------------------------
function openModal() { state.modalOpen = true; state.dropdownOpen = false; state.filterOpen = false; state.profileOpen = false; state.authView = null; render(); }
function closeOverlays() {
  state.modalOpen = false;
  state.dropdownOpen = false;
  state.filterOpen = false;
  state.profileOpen = false;
  state.authView = null;
  state.composeStep = null;
  state.composeJurOpen = false;
  render();
}

// new-post FAB: on another page it goes home to the Feed; on the Feed it composes
// (logged-out → register/login chooser; logged-in → the where/type/compose flow)
function onFabClick() {
  if (state.page !== "feed") { state.page = "feed"; render(); return; }
  if (!state.loggedIn) { state.authView = "choose"; render(); return; }
  startCompose();
}

// logged out: open the register/login chooser · logged in: toggle profile modal
function onAuthClick() {
  if (!state.loggedIn) { state.authView = state.authView ? null : "choose"; }
  else { state.profileOpen = !state.profileOpen; }
  render();
}
// passkey login resolves to a full signed-in session (demo) — closes the auth flow
function signIn() { state.loggedIn = true; state.authView = null; render(); }

// login modal body — all logins are passkey; the OTP path appears only in the allow window
function buildLoginInner() {
  var g = $("loginInner");
  while (g.firstChild) g.removeChild(g.firstChild);
  var CX = 215, y;

  if (state.otpAllowed) {
    g.appendChild(centerTxt(CX, 322, "Enter your email code — or use your passkey", 12, "#999"));
    otpRow(g, CX, 340, ["4", "7", "2", "9", "0", "5"]);
    // entering the OTP runs the Register-Passkey flow (enrol a passkey on this new device)
    g.appendChild(primaryBtn(79, 400, 272, "Register Passkey", "#ic-key", signIn));
    g.appendChild(outlineBtn(79, 458, 272, "Log In With Passkey", "#ic-key", signIn));
    y = 512;
  } else {
    g.appendChild(centerTxt(CX, 322, "Use your passkey to sign in", 12, "#999"));
    g.appendChild(primaryBtn(79, 346, 272, "Log In With Passkey", "#ic-key", signIn));
    y = 404;
  }

  var rec = document.createElementNS(SVG_NS, "g"); rec.style.cursor = "pointer";
  var rt = centerTxt(CX, y, "Lost your passkey? Recover account", 13, "#555");
  rt.setAttribute("text-decoration", "underline");
  rec.appendChild(rt);
  rec.addEventListener("click", function (e) { e.stopPropagation(); state.authView = "register"; render(); }); // reset reuses register flow
  g.appendChild(rec);
  y += 24;
  g.appendChild(centerTxt(CX, y, "Alt: O toggles the email-code (OTP) login window", 11, "#999"));
  y += 18;
  g.appendChild(centerTxt(CX, y, "Alt: Esc or tap outside to close", 11, "#999"));
  $("loginCard").setAttribute("height", (y + 14) - 250);
}
// small builders shared by the login body
function centerTxt(cx, y, s, size, fill) { var t = txt(cx, y, s, size, fill); t.setAttribute("text-anchor", "middle"); return t; }
function primaryBtn(x, y, w, label, ic, onClick) {
  var g = document.createElementNS(SVG_NS, "g"); g.style.cursor = "pointer";
  g.appendChild(rect(x, y, w, 46, 10, "#333"));
  g.appendChild(icon(ic, x + 37, y + 12, 22, "#fff"));
  var t = txt(x + w / 2 + 18, y + 29, label, 15, "#ffffff");
  t.setAttribute("text-anchor", "middle"); t.setAttribute("font-weight", "bold");
  g.appendChild(t);
  g.addEventListener("click", function (e) { e.stopPropagation(); onClick(); });
  return g;
}
function outlineBtn(x, y, w, label, ic, onClick) {
  var g = document.createElementNS(SVG_NS, "g"); g.style.cursor = "pointer";
  g.appendChild(rect(x, y, w, 46, 10, "#ffffff", "#333"));
  g.appendChild(icon(ic, x + 37, y + 12, 22, "#333"));
  var t = txt(x + w / 2 + 18, y + 29, label, 14, "#333");
  t.setAttribute("text-anchor", "middle");
  g.appendChild(t);
  g.addEventListener("click", function (e) { e.stopPropagation(); onClick(); });
  return g;
}
function logout() { state.loggedIn = false; state.profileOpen = false; render(); }

// ---- main render ---------------------------------------------------------
function render() {
  // My Districts requires a residency-verified account — never let it stick otherwise
  if (state.kyc < 2) state.myDistricts = false;

  // auth state + its callout
  show($("loginGlyph"), !state.loggedIn);
  show($("profileGlyph"), state.loggedIn);
  $("authCircle").setAttribute("fill", state.loggedIn ? "#333" : "#ffffff");
  $("annoLoginA").textContent = state.loggedIn ? "Signed in (avatar shown)" : "Logged out";
  $("annoLoginB").textContent = state.loggedIn ? "tap → profile (L to toggle)" : "tap → register / log in (L)";

  // selector label reflects the unified-feed filter
  $("curJur").textContent = pillLabel();

  // dropdown
  if (state.dropdownOpen) buildDropdown();
  show($("dropdown"), state.dropdownOpen);
  show($("modal"), state.modalOpen);

  // feed filter dropdown (left button)
  if (state.filterOpen) buildFilter();
  show($("filterDropdown"), state.filterOpen);

  // logged-out auth flow: chooser → register form → verify (OTP + passkey) · or → login
  var inAuth = !state.loggedIn;
  show($("authModal"),     inAuth && state.authView === "choose");
  show($("registerModal"), inAuth && state.authView === "register");
  show($("verifyModal"),   inAuth && state.authView === "verify");
  show($("loginModal"),    inAuth && state.authView === "login");
  if (inAuth && state.authView === "login") buildLoginInner();

  // spotlight result: if Alberta is already subscribed, offer Delete instead of Join
  var hasAlberta = state.subs.some(function (s) { return s.name === "Alberta"; });
  var act = $("albertaAction");
  act.textContent = hasAlberta ? "Delete ✕" : "Join ›";
  act.setAttribute("fill", hasAlberta ? "#c0392b" : "#999");

  // profile modal (only meaningful while logged in)
  show($("profileModal"), state.profileOpen && state.loggedIn);
  $("kycBadgeText").textContent = KYC_TIERS[state.kyc];
  $("kycBadge").querySelector("rect").setAttribute("fill", state.kyc === 0 ? "#f2f2f2" : "#333");
  $("kycBadgeText").setAttribute("fill", state.kyc === 0 ? "#555" : "#fff");
  $("kycShield").setAttribute("stroke", state.kyc === 0 ? "#666" : "#fff");
  $("deviceLabel").textContent = "Devices & passkeys (" + state.deviceCount + ")";
  var more = state.deviceCount - 2;
  var moreEl = $("deviceMore");
  moreEl.textContent = "+" + more + " more";
  show(moreEl, more > 0);

  // theme preference toggle (button only — no app-wide repaint)
  var dark = state.theme === "Dark";
  $("themeValue").textContent = state.theme;
  $("themeIcon").setAttribute("href", dark ? "#ic-moon" : "#ic-sun");
  $("themeIcon").setAttributeNS(XLINK, "href", dark ? "#ic-moon" : "#ic-sun");

  // compose flow: where → type → compose (logged-in only)
  show($("whereModal"),   state.loggedIn && state.composeStep === "where");
  show($("typeModal"),    state.loggedIn && state.composeStep === "type");
  show($("composeModal"), state.loggedIn && state.composeStep === "compose");
  if (state.composeStep === "where") buildWhere();
  if (state.composeStep === "type") buildType();
  if (state.composeStep === "compose") {
    var jn = state.composeJur || "Global", sub = subByName(jn), rm = rootMeta(state.composeType);
    $("composeJurName").textContent = jn;
    $("composeJurIcon").setAttribute("href", sub ? sub.icon : "#ic-globe");
    $("composeJurIcon").setAttributeNS(XLINK, "href", sub ? sub.icon : "#ic-globe");
    $("composeTypeLabel").textContent = rm.label;
    $("composeTypeIcon").setAttribute("href", rm.icon);
    $("composeTypeIcon").setAttributeNS(XLINK, "href", rm.icon);
    show($("composeChangeBtn"), rootsFor(jn).length > 1); // nothing to change if only one root
    buildComposeEditor();                                 // type-specific fields + Post
    if (state.composeJurOpen) buildComposeJurMenu();
    show($("composeJurMenu"), state.composeJurOpen);
  }

  // fab icon + callout depend on the current page
  show($("fabCompose"), state.page === "feed");
  show($("fabFeed"), state.page !== "feed");
  $("annoFabA").textContent = state.page === "feed" ? "On Feed" : "On another page";
  $("annoFabB").textContent = state.page === "feed" ? "tap → compose a post (quill)" : "tap → go to Feed (newspaper)";

  // labels: chrome shown unless the full-screen profile sheet covers it;
  // overlay callouts only while that overlay is open;
  // the include-filter callout only when checkboxes are actually shown
  show($("anno-chrome"), state.labelsOn && !state.profileOpen);
  show($("anno-dropdown"), state.labelsOn && state.dropdownOpen);
  show($("anno-dd-filter"), state.labelsOn && state.dropdownOpen && state.subs.length > 1);
  show($("anno-filter"), state.labelsOn && state.filterOpen);
  show($("anno-modal"), state.labelsOn && state.modalOpen);
  show($("anno-auth"), state.labelsOn && !!state.authView && !state.loggedIn);
  show($("anno-profile"), state.labelsOn && state.profileOpen && state.loggedIn);
}

// ---- wiring --------------------------------------------------------------
$("filterBtn").addEventListener("click", function () { state.filterOpen = !state.filterOpen; state.dropdownOpen = false; render(); });
$("selectorBtn").addEventListener("click", function () { state.dropdownOpen = !state.dropdownOpen; state.filterOpen = false; render(); });
$("authBtn").addEventListener("click", onAuthClick);
$("fab").addEventListener("click", onFabClick);
$("modalBackdrop").addEventListener("click", closeOverlays);
$("filterBackdrop").addEventListener("click", closeOverlays); // click outside → close
$("ddBackdrop").addEventListener("click", closeOverlays);     // click outside → close
$("modalCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });   // X button
$("profileCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); }); // X button
$("authCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });    // X button
$("resultAlberta").addEventListener("click", function () {
  var i = state.subs.findIndex(function (s) { return s.name === "Alberta"; });
  if (i === -1) {
    state.subs.push({ name: "Alberta", icon: "#ic-building", included: true });
  } else {
    state.subs.splice(i, 1); // already subscribed → Delete removes it
    // never leave the feed with nothing selected
    if (!state.subs.some(function (s) { return s.included; })) state.subs[0].included = true;
  }
  state.modalOpen = false;
  state.dropdownOpen = true; // reopen list so the change is visible
  render();
});

// chooser modal: pick register or login (logged-out only)
$("authBackdrop").addEventListener("click", closeOverlays);
$("registerBtn").addEventListener("click", function (e) { e.stopPropagation(); state.authView = "register"; render(); });
$("loginBtn").addEventListener("click", function (e) { e.stopPropagation(); state.authView = "login"; render(); });
$("recoverBtn").addEventListener("click", function (e) { e.stopPropagation(); state.authView = "register"; render(); }); // reset reuses register flow

// register form: submit sends the registration OTP email, then opens the verify page
$("registerBackdrop").addEventListener("click", closeOverlays);
$("registerCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });
$("regSubmitBtn").addEventListener("click", function (e) { e.stopPropagation(); state.authView = "verify"; render(); });

// verify page: enter OTP, tap Register Passkey → enrols this device's passkey and signs in
$("verifyBackdrop").addEventListener("click", closeOverlays);
$("verifyCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });
$("regPasskeyBtn").addEventListener("click", function (e) { e.stopPropagation(); signIn(); });
$("verifyResendBtn").addEventListener("click", function (e) { e.stopPropagation(); /* resend OTP — deferred */ });

// login modal (returning user): body + handlers are built in buildLoginInner()
$("loginBackdrop").addEventListener("click", closeOverlays);
$("loginCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });

// compose flow: where → type → compose
$("whereBackdrop").addEventListener("click", closeOverlays);
$("whereCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });
$("typeBackdrop").addEventListener("click", closeOverlays);
$("typeCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });
$("composeBackdrop").addEventListener("click", closeOverlays);
$("composeCloseBtn").addEventListener("click", function (e) { e.stopPropagation(); closeOverlays(); });
$("composeJurBtn").addEventListener("click", function (e) { e.stopPropagation(); state.composeJurOpen = !state.composeJurOpen; render(); });
$("composeChangeBtn").addEventListener("click", function (e) { e.stopPropagation(); state.composeStep = "type"; state.composeJurOpen = false; render(); });

// profile modal actions
$("profileBackdrop").addEventListener("click", closeOverlays);
$("logoutBtn").addEventListener("click", logout);
$("validateBtn").addEventListener("click", function (e) {
  e.stopPropagation();
  state.kyc = (state.kyc + 1) % KYC_TIERS.length; // demo: cycle the tier badge
  render();
});
$("addDeviceBtn").addEventListener("click", function (e) { e.stopPropagation(); state.deviceCount++; render(); });
$("addDeviceEmailBtn").addEventListener("click", function (e) { e.stopPropagation(); state.deviceCount++; render(); });

// direct account-settings items (each its own destination — deferred no-ops)
["editProfileBtn", "changeAddrBtn", "privacySettingsBtn", "jurisdictionsBtn", "termsBtn", "privacyBtn"].forEach(function (id) {
  $(id).addEventListener("click", function (e) { e.stopPropagation(); /* deferred */ });
});

// theme: live toggle (Light ↔ Dark) — preference only, no page flip
$("themeBtn").addEventListener("click", function (e) {
  e.stopPropagation();
  state.theme = (state.theme === "Light") ? "Dark" : "Light";
  render();
});

document.addEventListener("keydown", function (e) {
  switch (e.key) {
    case "l": case "L":
      // quick toggle: sign in / out (logging out also closes the profile)
      state.loggedIn = !state.loggedIn;
      if (!state.loggedIn) state.profileOpen = false;
      render();
      break;
    case "v": case "V": state.labelsOn = !state.labelsOn; render(); break;
    case "j": case "J": state.dropdownOpen = !state.dropdownOpen; state.filterOpen = false; render(); break;
    case "f": case "F": state.filterOpen = !state.filterOpen; state.dropdownOpen = false; render(); break;
    case "a": case "A": openModal(); break;
    case "o": case "O": state.otpAllowed = !state.otpAllowed; render(); break; // OTP-login window
    case "p": case "P": state.page = (state.page === "feed") ? "other" : "feed"; render(); break;
    case "Escape": closeOverlays(); break;
  }
});

render();
